import React, { useState, useEffect } from 'react';
import {
  BarChart, Bar, LineChart, Line, XAxis, YAxis, Tooltip,
  ResponsiveContainer, CartesianGrid, Legend
} from 'recharts';
import api from '../utils/api';
import Sidebar from '../components/common/Sidebar';

const downloadFile = async (endpoint, filename, setLoading) => {
  if (setLoading) setLoading(true);
  try {
    const response = await api.get(endpoint, { responseType: 'blob' });
    const ct = response.headers['content-type'] || '';
    const isXlsx = ct.includes('spreadsheet') || ct.includes('excel');
    const base = filename.replace(/\.(xlsx|csv)$/, '');
    const ext  = isXlsx ? '.xlsx' : '.csv';
    const blob = new Blob([response.data], { type: ct });
    const url  = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href  = url;
    link.setAttribute('download', base + ext);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  } catch (err) {
    console.error('Download failed:', err);
    alert('Download failed. Please try again.');
  } finally {
    if (setLoading) setLoading(false);
  }
};

const CustomTooltip = ({ active, payload, label }) => {
  if (!active || !payload?.length) return null;
  return (
    <div style={{ background: 'var(--bg-card)', border: '1px solid var(--border-light)', borderRadius: 6, padding: '0.6rem 0.85rem', fontSize: '0.8rem' }}>
      <div style={{ color: 'var(--text-muted)', marginBottom: '0.25rem' }}>{label}</div>
      {payload.map((p, i) => (
        <div key={i} style={{ color: p.color || 'var(--accent)', marginBottom: '0.15rem' }}>
          {p.name}: <strong>{p.value}</strong>
        </div>
      ))}
    </div>
  );
};

export default function ManagementDashboardPage() {
  const [data, setData]       = useState(null);
  const [loading, setLoading] = useState(true);
  const [exporting, setExporting] = useState(false);
  const [error, setError]     = useState('');

  useEffect(() => {
    setLoading(true);
    api.get('/dashboard/management')
      .then(r => { setData(r.data); setLoading(false); })
      .catch(err => {
        setError(err.response?.data?.error || 'Failed to load dashboard');
        setLoading(false);
      });
  }, []);

  // Demand vs completion trend — archived counts as completed
  const trendData = (data?.demandTrend || []).map(d => ({
    month:     new Date(d.month).toLocaleDateString('fr-FR', { month: 'short', year: '2-digit' }),
    submitted: parseInt(d.submitted || 0),
    completed: parseInt(d.completed || 0),  // includes archived
    rejected:  parseInt(d.rejected  || 0),
    cancelled: parseInt(d.cancelled || 0),
  }));

  const handleExport = (type) => {
    const endpointMap = {
      all:       '/export/requests/all',
      open:      '/export/requests/open',
      completed: '/export/requests/completed',
      overdue:   '/export/requests/overdue',
    };
    const filename = `3dprint-${type}-${new Date().toISOString().split('T')[0]}.xlsx`;
    downloadFile(endpointMap[type] || '/export/requests/all', filename, setExporting);
  };

  const sl = data?.serviceLevel;

  return (
    <div className="page">
      <Sidebar />
      <div className="main-content">
        <div className="page-header">
          <div>
            <div style={{ color: 'var(--text-muted)', fontSize: '0.72rem', marginBottom: '0.25rem' }}>
              Dashboards / Management Dashboard
            </div>
            <h1 style={{ fontSize: '1.3rem', fontFamily: 'var(--font-heading)' }}>Management Dashboard</h1>
            <p style={{ color: 'var(--text-muted)', fontSize: '0.8rem', marginTop: '0.2rem' }}>
              Strategic overview — archived requests counted in historical KPIs
            </p>
          </div>
          <div style={{ display: 'flex', gap: '0.5rem', flexWrap: 'wrap' }}>
            {[['all','All'],['open','Open'],['completed','Completed'],['overdue','Overdue']].map(([type, label]) => (
              <button
                key={type}
                className="btn btn-secondary btn-sm"
                onClick={() => handleExport(type)}
                disabled={exporting}
              >
                {exporting
                  ? <><span className="spinner" style={{ width: 11, height: 11 }}/> …</>
                  : `↓ ${label}`
                }
              </button>
            ))}
          </div>
        </div>

        <div className="page-body">
          {error && <div className="alert alert-error" style={{ marginBottom: '1rem' }}>{error}</div>}

          {loading ? (
            <div style={{ display: 'flex', justifyContent: 'center', padding: '3rem' }}>
              <span className="spinner" style={{ width: 32, height: 32 }}/>
            </div>
          ) : (
            <>
              {/* Service Level KPIs — correct open count */}
              <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(140px,1fr))', gap: '1rem', marginBottom: '1.5rem' }}>
                <div className="kpi-card">
                  <div className="kpi-value" style={{ color: 'var(--blue)' }}>{sl?.open ?? 0}</div>
                  <div className="kpi-label">Open Requests</div>
                  <div style={{ fontSize: '0.7rem', color: 'var(--text-muted)', marginTop: '0.2rem' }}>
                    Active in workflow
                  </div>
                </div>
                <div className="kpi-card">
                  <div className="kpi-value" style={{ color: 'var(--green)' }}>{sl?.completed ?? 0}</div>
                  <div className="kpi-label">Completed</div>
                  <div style={{ fontSize: '0.7rem', color: 'var(--text-muted)', marginTop: '0.2rem' }}>
                    incl. archived
                  </div>
                </div>
                <div className="kpi-card">
                  <div className="kpi-value" style={{ color: 'var(--red)' }}>{sl?.rejected ?? 0}</div>
                  <div className="kpi-label">Rejected</div>
                </div>
                <div className="kpi-card">
                  <div className="kpi-value" style={{ color: 'var(--text-muted)' }}>{sl?.cancelled ?? 0}</div>
                  <div className="kpi-label">Cancelled</div>
                </div>
                <div className="kpi-card">
                  <div className="kpi-value" style={{ color: (sl?.overdue ?? 0) > 0 ? 'var(--red)' : 'var(--green)' }}>
                    {sl?.overdue ?? 0}
                  </div>
                  <div className="kpi-label">Overdue</div>
                </div>
                <div className="kpi-card">
                  <div className="kpi-value" style={{ color: (sl?.blocked ?? 0) > 0 ? 'var(--yellow)' : 'var(--green)' }}>
                    {sl?.blocked ?? 0}
                  </div>
                  <div className="kpi-label">Blocked</div>
                </div>
              </div>

              {/* Demand vs Completion Trend */}
              <div className="card" style={{ marginBottom: '1.5rem' }}>
                <h3 style={{ fontSize: '0.8rem', color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '0.08em', marginBottom: '0.5rem' }}>
                  Demand vs Completion Trend (6 months)
                </h3>
                <p style={{ fontSize: '0.75rem', color: 'var(--text-muted)', marginBottom: '1rem' }}>
                  "Completed" includes archived requests — archived = completed historically.
                </p>
                {trendData.length > 0 ? (
                  <ResponsiveContainer width="100%" height={240}>
                    <LineChart data={trendData}>
                      <CartesianGrid strokeDasharray="3 3" stroke="var(--border)" vertical={false}/>
                      <XAxis dataKey="month" tick={{ fill: 'var(--text-muted)', fontSize: 11 }} axisLine={false} tickLine={false}/>
                      <YAxis tick={{ fill: 'var(--text-muted)', fontSize: 11 }} axisLine={false} tickLine={false} width={28} allowDecimals={false}/>
                      <Tooltip content={<CustomTooltip/>}/>
                      <Legend wrapperStyle={{ fontSize: '0.78rem' }}/>
                      <Line type="monotone" dataKey="submitted" stroke="var(--blue)"   strokeWidth={2} dot={{ r: 4, fill: 'var(--blue)' }}   name="Submitted"/>
                      <Line type="monotone" dataKey="completed" stroke="var(--green)"  strokeWidth={2} dot={{ r: 4, fill: 'var(--green)' }}  name="Completed"/>
                      <Line type="monotone" dataKey="rejected"  stroke="var(--red)"    strokeWidth={1} strokeDasharray="4 2" dot={{ r: 3 }} name="Rejected"/>
                    </LineChart>
                  </ResponsiveContainer>
                ) : (
                  <div className="empty-state" style={{ padding: '2rem' }}>
                    <p>No trend data yet — data appears after the first month</p>
                  </div>
                )}
              </div>

              <div className="grid-2" style={{ marginBottom: '1.5rem' }}>
                {/* Top categories */}
                <div className="card">
                  <h3 style={{ fontSize: '0.8rem', color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '0.08em', marginBottom: '1rem' }}>
                    Top Request Categories
                  </h3>
                  {data?.topCategories?.length > 0 ? (
                    <ResponsiveContainer width="100%" height={200}>
                      <BarChart
                        data={data.topCategories.map(c => ({ name: c.name || 'Unknown', count: parseInt(c.count) }))}
                        layout="vertical"
                        barSize={16}
                      >
                        <XAxis type="number" tick={{ fill: 'var(--text-muted)', fontSize: 11 }} axisLine={false} tickLine={false}/>
                        <YAxis type="category" dataKey="name" tick={{ fill: 'var(--text-secondary)', fontSize: 11 }} axisLine={false} tickLine={false} width={110}/>
                        <Tooltip content={<CustomTooltip/>}/>
                        <Bar dataKey="count" fill="var(--accent)" radius={[0,4,4,0]} name="Requests"/>
                      </BarChart>
                    </ResponsiveContainer>
                  ) : (
                    <div className="empty-state" style={{ padding: '2rem' }}><p>No category data yet</p></div>
                  )}
                </div>

                {/* Bottlenecks */}
                <div className="card">
                  <h3 style={{ fontSize: '0.8rem', color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '0.08em', marginBottom: '1rem' }}>
                    Current Bottlenecks
                  </h3>
                  {data?.bottlenecks?.length > 0 ? (
                    data.bottlenecks.map((b, i) => {
                      const labels = {
                        more_info_required:   'Waiting for requester info',
                        blocked:              'Blocked — needs intervention',
                        on_hold:              'On Hold',
                        waiting_for_material: 'Waiting for material',
                        waiting_for_machine:  'Waiting for machine',
                        rework_required:      'Rework required',
                        waiting_for_input:    'Waiting for input',
                      };
                      const colors = {
                        blocked:              'var(--red)',
                        rework_required:      'var(--accent)',
                        more_info_required:   'var(--yellow)',
                        on_hold:              'var(--yellow)',
                        waiting_for_material: 'var(--cyan)',
                        waiting_for_machine:  'var(--cyan)',
                        waiting_for_input:    'var(--yellow)',
                      };
                      const col = colors[b.status] || 'var(--accent)';
                      return (
                        <div key={i} style={{
                          display: 'flex', alignItems: 'center', justifyContent: 'space-between',
                          padding: '0.85rem 1rem', background: 'var(--bg-hover)',
                          borderRadius: 8, marginBottom: '0.5rem',
                          borderLeft: `3px solid ${col}`,
                        }}>
                          <div style={{ fontSize: '0.82rem', color: 'var(--text-secondary)' }}>
                            {labels[b.status] || b.status.replace(/_/g,' ')}
                          </div>
                          <div style={{ fontFamily: 'var(--font-heading)', fontSize: '1.2rem', fontWeight: 800, color: col }}>
                            {b.count}
                          </div>
                        </div>
                      );
                    })
                  ) : (
                    <div className="empty-state" style={{ padding: '2rem' }}>
                      <p style={{ color: 'var(--green)' }}>✓ No bottlenecks detected</p>
                    </div>
                  )}
                </div>
              </div>

              {/* Coordinator performance */}
              {data?.coordinatorPerf && (
                <div className="card">
                  <h3 style={{ fontSize: '0.8rem', color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '0.08em', marginBottom: '1rem' }}>
                    Coordinator Performance
                  </h3>
                  <div style={{ display: 'flex', gap: '2rem', flexWrap: 'wrap' }}>
                    <div>
                      <div style={{ fontSize: '1.5rem', fontFamily: 'var(--font-heading)', fontWeight: 800, color: 'var(--blue)' }}>
                        {data.coordinatorPerf.avg_review_hours
                          ? `${data.coordinatorPerf.avg_review_hours}h`
                          : '—'}
                      </div>
                      <div style={{ fontSize: '0.75rem', color: 'var(--text-muted)' }}>Avg. review time (submit → approve)</div>
                    </div>
                    <div>
                      <div style={{ fontSize: '1.5rem', fontFamily: 'var(--font-heading)', fontWeight: 800, color: 'var(--green)' }}>
                        {data.coordinatorPerf.total_completed || 0}
                      </div>
                      <div style={{ fontSize: '0.75rem', color: 'var(--text-muted)' }}>Total completed</div>
                    </div>
                    <div>
                      <div style={{ fontSize: '1.5rem', fontFamily: 'var(--font-heading)', fontWeight: 800, color: 'var(--red)' }}>
                        {data.coordinatorPerf.total_rejected || 0}
                      </div>
                      <div style={{ fontSize: '0.75rem', color: 'var(--text-muted)' }}>Total rejected</div>
                    </div>
                    <div>
                      <div style={{ fontSize: '1.5rem', fontFamily: 'var(--font-heading)', fontWeight: 800, color: 'var(--yellow)' }}>
                        {data.coordinatorPerf.total_open || 0}
                      </div>
                      <div style={{ fontSize: '0.75rem', color: 'var(--text-muted)' }}>Currently open</div>
                    </div>
                  </div>
                </div>
              )}
            </>
          )}
        </div>
      </div>
    </div>
  );
}
